import React, { useState, useRef, useEffect } from 'react';
import {
  View, StyleSheet, FlatList, TouchableOpacity, Animated, Dimensions,
} from 'react-native';
import { Text, Divider } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';

const { width } = Dimensions.get('window');

export default function CartScreen({ navigation }) {
  const [cartItems, setCartItems] = useState([
    { id: 1, name: 'Fresh Tomatoes', price: 40, quantity: 2, unit: 'kg', farmer: 'Rajesh Kumar', image: '🍅', gradient: ['#FF6B6B', '#EE5A24'] },
    { id: 2, name: 'Organic Spinach', price: 30, quantity: 1, unit: 'kg', farmer: 'Priya Sharma', image: '🥬', gradient: ['#00C853', '#00E676'] },
  ]);

  const headerAnim = useRef(new Animated.Value(0)).current;
  useEffect(() => {
    Animated.timing(headerAnim, { toValue: 1, duration: 500, useNativeDriver: true }).start();
  }, []);

  const updateQuantity = (id, delta) => {
    setCartItems(items => items.map(item =>
      item.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item
    ));
  };

  const removeItem = (id) => {
    setCartItems(items => items.filter(item => item.id !== id));
  };

  const subtotal = cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0);
  const deliveryFee = 30;
  const total = subtotal + deliveryFee;

  const renderCartItem = ({ item, index }) => (
    <AnimatedCartItem item={item} index={index} updateQuantity={updateQuantity} removeItem={removeItem} />
  );

  return (
    <LinearGradient colors={['#0a1a0f', '#0d2818', '#0a1a0f']} style={styles.container}>
      {/* Header */}
      <Animated.View style={[styles.header, { opacity: headerAnim }]}>
        <Text style={styles.headerTitle}>My Cart</Text>
        <View style={styles.itemCountBadge}>
          <Text style={styles.itemCountText}>{cartItems.length}</Text>
        </View>
      </Animated.View>

      {cartItems.length === 0 ? (
        <View style={styles.emptyContainer}>
          <View style={styles.emptyIconWrapper}>
            <Icon name="cart-outline" size={60} color="rgba(255,255,255,0.15)" />
          </View>
          <Text style={styles.emptyTitle}>Your cart is empty</Text>
          <Text style={styles.emptySubtitle}>Add some fresh produce to get started</Text>
          <TouchableOpacity activeOpacity={0.8} onPress={() => navigation.navigate('Products')}>
            <LinearGradient colors={['#00C853', '#00E676']} style={styles.shopButton}>
              <Icon name="shopping" size={20} color="#0a1a0f" style={{ marginRight: 8 }} />
              <Text style={styles.shopButtonText}>Browse Products</Text>
            </LinearGradient>
          </TouchableOpacity>
        </View>
      ) : (
        <>
          <FlatList
            data={cartItems}
            renderItem={renderCartItem}
            keyExtractor={item => item.id.toString()}
            style={styles.list}
            contentContainerStyle={{ paddingBottom: 20 }}
            showsVerticalScrollIndicator={false}
          />

          {/* Summary */}
          <View style={styles.summaryContainer}>
            <LinearGradient colors={['rgba(255,255,255,0.08)', 'rgba(255,255,255,0.03)']} style={styles.summaryGlass}>
              <View style={styles.summaryRow}>
                <Text style={styles.summaryLabel}>Subtotal</Text>
                <Text style={styles.summaryValue}>₹{subtotal}</Text>
              </View>
              <View style={styles.summaryRow}>
                <Text style={styles.summaryLabel}>Delivery Fee</Text>
                <Text style={styles.summaryValue}>₹{deliveryFee}</Text>
              </View>
              <View style={styles.divider} />
              <View style={styles.summaryRow}>
                <Text style={styles.totalLabel}>Total</Text>
                <Text style={styles.totalValue}>₹{total}</Text>
              </View>
              <TouchableOpacity activeOpacity={0.8} onPress={() => alert('Proceeding to checkout...')}>
                <LinearGradient colors={['#00C853', '#00E676']} start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }} style={styles.checkoutButton}>
                  <Text style={styles.checkoutText}>Checkout</Text>
                  <View style={styles.checkoutPrice}>
                    <Text style={styles.checkoutPriceText}>₹{total}</Text>
                  </View>
                </LinearGradient>
              </TouchableOpacity>
            </LinearGradient>
          </View>
        </>
      )}
    </LinearGradient>
  );
}

function AnimatedCartItem({ item, index, updateQuantity, removeItem }) {
  const anim = useRef(new Animated.Value(0)).current;
  useEffect(() => {
    Animated.spring(anim, { toValue: 1, delay: index * 100, tension: 50, friction: 8, useNativeDriver: true }).start();
  }, []);
  return (
    <Animated.View style={{ opacity: anim, transform: [{ translateX: anim.interpolate({ inputRange: [0, 1], outputRange: [-50, 0] }) }] }}>
      <View style={styles.cartItemContainer}>
        <View style={styles.cartItem}>
          <View style={styles.itemImageWrapper}>
            <LinearGradient colors={item.gradient} style={styles.itemImgBg}>
              <Text style={styles.itemEmoji}>{item.image}</Text>
            </LinearGradient>
          </View>
          <View style={styles.itemDetails}>
            <Text style={styles.itemName}>{item.name}</Text>
            <Text style={styles.itemFarmer}>{item.farmer}</Text>
            <Text style={styles.itemPrice}>₹{item.price}/{item.unit}</Text>
          </View>
          <View style={styles.itemActions}>
            <View style={styles.quantityControls}>
              <TouchableOpacity style={styles.qtyBtn} onPress={() => updateQuantity(item.id, -1)}>
                <Icon name="minus" size={14} color="#fff" />
              </TouchableOpacity>
              <Text style={styles.qtyValue}>{item.quantity}</Text>
              <TouchableOpacity style={styles.qtyBtn} onPress={() => updateQuantity(item.id, 1)}>
                <Icon name="plus" size={14} color="#fff" />
              </TouchableOpacity>
            </View>
            <TouchableOpacity onPress={() => removeItem(item.id)} style={styles.deleteBtn}>
              <Icon name="trash-can-outline" size={18} color="#FF5252" />
            </TouchableOpacity>
          </View>
        </View>
      </View>
    </Animated.View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  header: { flexDirection: 'row', alignItems: 'center', paddingHorizontal: 24, paddingTop: 60, paddingBottom: 16 },
  headerTitle: { fontSize: 28, fontWeight: '800', color: '#fff', letterSpacing: -0.5 },
  itemCountBadge: { marginLeft: 12, backgroundColor: '#00C853', paddingHorizontal: 10, paddingVertical: 4, borderRadius: 10 },
  itemCountText: { fontSize: 13, fontWeight: '700', color: '#0a1a0f' },
  list: { flex: 1 },
  cartItemContainer: { paddingHorizontal: 20, marginBottom: 12 },
  cartItem: { flexDirection: 'row', backgroundColor: 'rgba(255,255,255,0.05)', borderRadius: 18, padding: 14, borderWidth: 1, borderColor: 'rgba(255,255,255,0.06)', alignItems: 'center' },
  itemImageWrapper: { width: 60, height: 60, borderRadius: 16, overflow: 'hidden' },
  itemImgBg: { flex: 1, justifyContent: 'center', alignItems: 'center' },
  itemEmoji: { fontSize: 32 },
  itemDetails: { flex: 1, marginLeft: 14 },
  itemName: { fontSize: 15, fontWeight: '700', color: '#fff' },
  itemFarmer: { fontSize: 12, color: 'rgba(255,255,255,0.4)', marginTop: 2 },
  itemPrice: { fontSize: 14, color: '#00C853', fontWeight: '700', marginTop: 4 },
  itemActions: { alignItems: 'flex-end' },
  quantityControls: { flexDirection: 'row', alignItems: 'center', backgroundColor: 'rgba(255,255,255,0.06)', borderRadius: 12, borderWidth: 1, borderColor: 'rgba(255,255,255,0.08)' },
  qtyBtn: { width: 32, height: 32, justifyContent: 'center', alignItems: 'center' },
  qtyValue: { fontSize: 14, fontWeight: '700', color: '#fff', marginHorizontal: 8 },
  deleteBtn: { marginTop: 8 },
  summaryContainer: { paddingHorizontal: 20, paddingBottom: 100 },
  summaryGlass: { borderRadius: 20, padding: 20, borderWidth: 1, borderColor: 'rgba(255,255,255,0.08)' },
  summaryRow: { flexDirection: 'row', justifyContent: 'space-between', marginBottom: 12 },
  summaryLabel: { fontSize: 14, color: 'rgba(255,255,255,0.4)' },
  summaryValue: { fontSize: 14, color: 'rgba(255,255,255,0.7)' },
  divider: { height: 1, backgroundColor: 'rgba(255,255,255,0.08)', marginVertical: 8 },
  totalLabel: { fontSize: 18, fontWeight: '700', color: '#fff' },
  totalValue: { fontSize: 22, fontWeight: '800', color: '#00C853' },
  checkoutButton: { flexDirection: 'row', alignItems: 'center', justifyContent: 'center', paddingVertical: 16, borderRadius: 16, marginTop: 16 },
  checkoutText: { fontSize: 17, fontWeight: '700', color: '#0a1a0f', marginRight: 10 },
  checkoutPrice: { backgroundColor: 'rgba(0,0,0,0.15)', paddingHorizontal: 12, paddingVertical: 4, borderRadius: 10 },
  checkoutPriceText: { fontSize: 15, fontWeight: '800', color: '#0a1a0f' },
  emptyContainer: { flex: 1, justifyContent: 'center', alignItems: 'center', paddingHorizontal: 40 },
  emptyIconWrapper: { width: 100, height: 100, borderRadius: 32, backgroundColor: 'rgba(255,255,255,0.04)', justifyContent: 'center', alignItems: 'center', marginBottom: 20 },
